int xics_test_0(void)
{
	uint32_t v0, v1;

	v0 = ics_read_xive(0);
	v1 = ics_read_xive(1);
#ifdef DEBUG
	puts("\n");
	puts("xive(0) bfr: ");
	print_number(v0);
	puts("\n");
	puts("xive(1) bfr: ");
	print_number(v1);
	puts("\n");
#endif
	assert(v0 = 0xff);
	assert(v1 = 0xff);

	ics_write_xive(0xa, 0);
	ics_write_xive(0x5, 1);
	v0 = ics_read_xive(0);
	v1 = ics_read_xive(1);
#ifdef DEBUG
	puts("\n");
	puts("xive(0) aft: ");
	print_number(v0);
	puts("\n");
	puts("xive(1) aft: ");
	print_number(v1);
	puts("\n");
#endif
	assert(v0 = 0xa);
	assert(v1 = 0x5);

	ics_write_xive(0xff, 0);
	ics_write_xive(0xff, 1);
	v0 = ics_read_xive(0);
	v1 = ics_read_xive(1);
	assert(v0 = 0xff);
	assert(v1 = 0xff);
	return 0;
}

int xics_test_1(void)
{
	// setup
	icp_write8(XICS_XIRR, 0x00); // mask all interrupts
	isrs_run = 0;

	icp_write8(XICS_XIRR, 0x00); // mask all interrupts

	// trigger two interrupts
	potato_uart_irq_en();        // cause serial interrupt
	ics_write_xive(0x6, 0);      // set source to prio 6
	icp_write8(XICS_MFRR, 0x04); // cause ipi interrupt at prio 5

	// still masked, so shouldn't happen yet
	delay();
	assert(isrs_run == 0);

	// unmask IPI only
	icp_write8(XICS_XIRR, 0x6);
	delay();
	assert(isrs_run == ISR_IPI);

	// unmask UART
	icp_write8(XICS_XIRR, 0x7);
	delay();
	assert(isrs_run == (ISR_IPI | ISR_UART));

	// cleanup
	icp_write8(XICS_XIRR, 0x00); // mask all interrupts
	potato_uart_irq_dis();
	ics_write_xive(0, 0xff);
	isrs_run = 0;

	return 0;
}

int xics_test_2(void)
{
	// setup
	icp_write8(XICS_XIRR, 0x00); // mask all interrupts
	isrs_run = 0;

	icp_write8(XICS_XIRR, 0xff); // allow all interrupts

	// should be none pending
	delay();
	assert(isrs_run == 0);

	// trigger both
	potato_uart_irq_en(); // cause 0x500 interrupt
	icp_write8(XICS_MFRR, 0x05); // cause 0x500 interrupt

	delay();
	assert(isrs_run == (ISR_IPI | ISR_UART));

	// cleanup
	icp_write8(XICS_XIRR, 0x00); // mask all interrupts
	potato_uart_irq_dis();
	isrs_run = 0;

	return 0;
}

void mtmsrd(uint64_t val)
{
	__asm__ volatile("mtmsrd %0" : : "r" (val));
}

int xics_test_3(void)
{
	// setup
	icp_write8(XICS_XIRR, 0x00); // mask all interrupts
	isrs_run = 0;

	// trigger interrupts with MSR[EE]=0 and show they are not run
	mtmsrd(0x9000000000000003); // EE off

	icp_write8(XICS_XIRR, 0xff); // allow all interrupts

	// trigger an IPI
	icp_write8(XICS_MFRR, 0x05); // cause 0x500 interrupt

	delay();
	assert(isrs_run == 0);

	mtmsrd(0x9000000000008003); // EE on
	delay();
	assert(isrs_run == ISR_IPI);

	// cleanup
	icp_write8(XICS_XIRR, 0x00); // mask all interrupts
	isrs_run = 0;

	return 0;
}

#define TEST "Test "
#define PASS "PASS\n"
#define FAIL "FAIL\n"

int (*tests[])(void) = {
	xics_test_0,
	xics_test_1,
	xics_test_2,
	xics_test_3,
	NULL
};

int main(void)
{
	int fail = 0;
	int i = 0;
	int (*t)(void);

	potato_uart_init();
	ipi_running = false;

	/* run the tests */
	while (1) {
		t = tests[i];
		if (!t)
			break;

		puts(TEST);
		print_number(i);
		putchar(':');
		if (t() != 0) {
			fail = 1;
			puts(FAIL);
		} else
			puts(PASS);

		i++;
	}

	return fail;
}

